const history = JSON.parse(localStorage.getItem('clipHistory') || '[]');
let filteredHistory = [...history];

function renderHistory() {
  const container = document.getElementById('history');
  const search = document.getElementById('search').value.toLowerCase();
  filteredHistory = history.filter(item => item.text.toLowerCase().includes(search));

  container.innerHTML = filteredHistory.length === 0 
    ? '<div class="text-center text-slate-500 py-8">No items</div>'
    : filteredHistory.map((item, i) => `
      <div class="clip-item p-2 rounded-lg bg-slate-800 cursor-pointer group" data-index="${i}">
        <div class="text-sm text-slate-200 truncate">${escapeHtml(item.text.slice(0, 100))}</div>
        <div class="text-xs text-slate-500 mt-1 flex justify-between">
          <span>${new Date(item.time).toLocaleTimeString()}</span>
          <span class="opacity-0 group-hover:opacity-100">Click to paste</span>
        </div>
      </div>
    `).join('');

  document.getElementById('count').textContent = `${filteredHistory.length} items`;
}

function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

// Add current clipboard to history
async function captureClipboard() {
  const result = await stuard.callTool('get_clipboard_content');
  if (result.ok && result.text && result.text.trim()) {
    const exists = history.find(h => h.text === result.text);
    if (!exists) {
      history.unshift({ text: result.text, time: Date.now() });
      if (history.length > 50) history.pop();
      localStorage.setItem('clipHistory', JSON.stringify(history));
      renderHistory();
    }
  }
}

// Click to paste
document.getElementById('history').addEventListener('click', async (e) => {
  const item = e.target.closest('.clip-item');
  if (item) {
    const index = parseInt(item.dataset.index);
    const text = filteredHistory[index].text;
    await stuard.copyToClipboard(text);
    stuard.close({ action: 'paste', text });
  }
});

// Search
document.getElementById('search').addEventListener('input', renderHistory);

// Clear all
document.getElementById('clear-all').addEventListener('click', () => {
  history.length = 0;
  localStorage.setItem('clipHistory', '[]');
  renderHistory();
});

// Focus search on open
document.getElementById('search').focus();

// Escape to close
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') stuard.close();
  if (e.key === 'Enter' && filteredHistory.length > 0) {
    stuard.copyToClipboard(filteredHistory[0].text);
    stuard.close({ action: 'paste', text: filteredHistory[0].text });
  }
});

captureClipboard();
renderHistory();
